import React from 'react';
import './TransferProgress.css';

const TransferProgress = ({ activeTransfers }) => {
  if (!activeTransfers || activeTransfers.length === 0) return null;

  return (
    <div className="transfer-panel card fade-in">
      <h3 className="transfer-panel-title">Active Transfers</h3>
      <div className="transfer-list">
        {activeTransfers.map((transfer) => (
          <div key={transfer.id} className="transfer-item">
            <div className="transfer-info">
              <span className="transfer-filename" title={transfer.fileName}>{transfer.fileName}</span>
              <span className="transfer-percentage">{Math.round(transfer.progress)}%</span>
            </div>
            <div className="progress-bar-container">
              <div 
                className={`progress-bar-fill ${transfer.type === 'upload' ? 'uploading' : 'downloading'}`}
                style={{ width: `${transfer.progress}%` }}
              />
            </div>
            <div className="transfer-meta">
              <span>{transfer.type === 'upload' ? '⬆️ Uploading to' : '⬇️ Downloading from'} {transfer.peerName || 'Network'}</span>
              <span>{transfer.speed || 'Calculating...'}</span>
            </div>
          </div>
        ))}
      </div>
    </div>
  );
};

export default TransferProgress;
